def language_context(request):
    code = request.session.get("language", "fr")
    if code not in LANGUAGES:
        code = "fr"
    return {
        "language_code": code,
        "language_dir": LANGUAGES[code]["dir"],
        "languages": LANGUAGES,
        "ui": UI[code],
        "role_text": ROLES[code],
        "game_text": GAME[code],
    }
